

export default {
  layout: 'login',
  props: {
    imgSrc: {
      type: Object,
      default: null
    }
  },

  data () {
    return {
      zoom: 1,
      resultImage: null,
      imageData: null,
      tempIndex: 1,
      imageUpload: false
    }
  },
  destroyed () {
    if (this.imgSrc.img) {
      URL.revokeObjectURL(this.imgSrc.img)
    }
  },
  mounted () {
    this.$refs.cropper.refresh()
    this.imageData = null
  },
  methods: {
    percentsRestriction ({ minWidth, minHeight, maxWidth, maxHeight, imageWidth, imageHeight }) {
      return {
        minWidth,
        minHeight,
        maxWidth,
        maxHeight
      }
    },
    dataURLtoFile (dataurl, filename) {
      const arr = dataurl.split(',')
      const mime = arr[0].match(/:(.*?);/)[1]
      const bstr = atob(arr[1])
      let n = bstr.length
      const u8arr = new Uint8Array(n)

      while (n--) {
        u8arr[n] = bstr.charCodeAt(n)
      }

      return new File([u8arr], filename, { type: mime })
    },
    async applyChange () {
      this.imageUpload = true
      const canvas = this.$refs.cropper.getResult()
      this.resultImage = canvas.canvas.toDataURL()
      const file = this.dataURLtoFile(this.resultImage, 'result_crop_' + Date.now() + this.tempIndex++)
      const data = new FormData()
      data.append('files', file)
      await this.$axios
        .post('obs/array', data, {
          headers: {
            'Content-Type': 'application/json'
          }
        })
        .then((res) => {
          const fileKey = this.$config.baseURL + 'obs?fileKey=' + res.data.data.fileKeys[0]
          const dataFile = {
            status: 'ready',
            name: 'result_crop_' + Date.now() + this.tempIndex++,
            size: file.size,
            percentage: 0,
            uid: '-',
            raw: file
          }
          const data = {
            indexRawImage: this.imgSrc.indexRawImage,
            indexForm: this.imgSrc.indexForm,
            title: this.imgSrc.title,
            type: this.imgSrc.type,
            src: fileKey,
            data: dataFile
          }
          this.$emit('saveEditor', data)
          this.imageUpload = false
        })
        .catch((error) => {
          this.$notifier.showMessage({
            content: 'Upload failed. Please try again ! ' + error,
            type: 'failed'
          })
          this.imageUpload = false
        })
    },
    onZoom (x) {
      if (x === 'in') {
        const zoom = 1
        this.zoom = zoom + 1
        this.$refs.cropper.zoom(this.zoom)
      } else {
        this.$refs.cropper.zoom(0.5)
      }
    },
    move (x) {
      if (x === 'up') {
        this.$refs.cropper.move(0, -100)
      }
      if (x === 'down') {
        this.$refs.cropper.move(0, 100)
      }
      if (x === 'left') {
        this.$refs.cropper.move(-100, 0)
      }
      if (x === 'right') {
        this.$refs.cropper.move(100, 0)
      }
    },
    close () {
      this.$emit('closeEditor', false)
      this.$store.commit('user/SET_DROPDOWN', null)
    },
    changeImage (file) {
      const { files } = event.target
      if (files && files[0]) {
        const formatData = files[0].type
        if (
          formatData === 'image/jpg' ||
          formatData === 'image/jpeg' ||
          formatData === 'image/png' ||
          formatData === 'image/gif' ||
          formatData === 'image/bmp'
        ) {
          if (files[0].size / 1023.4 > 500) {
            this.$message.error('Image size can not exceed 500KB!')
          } else {
            if (this.imgSrc.img) {
              URL.revokeObjectURL(this.imgSrc.img)
            }
            file.uid = Date.now() + this.tempIndex++
            const dataFile = {
              status: 'ready',
              name: files[0].name,
              size: files[0].size,
              percentage: 0,
              uid: file.uid,
              raw: files[0]
            }
            this.imageData = dataFile
            this.getBase64(files[0]).then((res) => {
              const params = res.split(',')
              if (params.length > 0) {
                this.imgBase64 = params[1]
                this.imgSrc.img = 'data:image/png;base64, ' + params[1]
              }
            })
          }
        } else {
          this.$message.error('Image must be JPG, JPEG, PNG, GIF & BMP format')
        }
      }
    },
    getBase64 (file) {
      return new Promise(function (resolve, reject) {
        const reader = new FileReader()
        let imgResult = ''
        reader.readAsDataURL(file)
        reader.onload = function () {
          imgResult = reader.result
        }
        reader.onerror = function (error) {
          reject(error)
        }
        reader.onloadend = function () {
          resolve(imgResult)
        }
      })
    }
  }
}
